INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6f0ba476-moex-00109', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於侵權行為之敘述，何者錯誤？', '["甲、乙、丙三人各自臨時起意，在山上朝登山客丁所在之位置丟擲石頭，而其中一塊石頭恰擊 中丁，致丁受傷。若不知何人丟擲之石頭擊中丁，則由甲、乙、丙三人負連帶損害賠償責任", "無行為能力人甲不慎打破乙所有之A骨董，而其行為時無識別能力。若甲之法定代理人丙違反 其監督義務並具有過失，則由丙單獨對乙負損害賠償責任", "定作人甲委請承攬人乙為其設計並興建B平房，且全面聽從乙之意見及指示。若乙因一時施工 不慎，致鄰宅之牆壁龜裂，則甲不負損害賠償責任", "甲現為職業駕駛，某日駕駛其妻乙所有之C車欲接送子女。若甲於途中不慎撞傷路人丙，則甲、 乙兩人負連帶損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00110', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於抵銷之敘述，何者正確？', '["禁止扣押之債，其債權人不得主張抵銷", "因故意侵權行為而負擔之債，其債權人得主張抵銷", "抵銷，於一方當事人向他方以意思表示為之時發生效力", "抵銷之意思表示得附條件，但不得附期限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00111', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲與乙訂立承攬契約，約定乙於15日內，改裝甲之廚房。下列敘述，何者正確？', '["乙得將一部分工程轉由第三人丙協助完成", "若約定由乙提供改裝材料，推定價額外應另支付材料價金", "依民法規定，甲應先支付全額報酬，始得請求乙完成全部工作", "甲得隨時與乙終止契約，且無須任何賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00112', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於和解契約效力之敘述，何者正確?', '["和解契約合法成立後，若當事人兩造皆不願維持，得合意解除該契約", "和解契約若以無因性債務拘束替代原有法律關係，乃具有認定效力", "和解契約乃互相讓步，一方須拋棄權利，乃屬於有償單務契約", "和解契約乃創設形成一新法律關係，故具有物權效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00113', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於使用借貸之敘述，何者錯誤？', '["使用借貸須為有償貸與使用", "借用人就借用物支出有益費用，因而增加該物之價值時，如貸與人知其情事而已為反對之表示 時，無償還義務", "數人共借一物時，如因其中一人之過失而毀損該借用物，各借用人對於貸與人應連帶負責", "借用人未經貸與人同意，即允許第三人使用借用物時，貸與人得終止契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00114', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者無須負連帶賠償責任?', '["甲、乙超速互撞，卻波及路旁行人丙，造成丙受重傷", "甲因經營不善，無法給付貨款於丙，遂將其商號經營，由乙概括承受", "甲委由乙代為處理二手車銷售事宜，然乙遲未將該二手車交付於丙", "甲、乙以每月2萬元共同向丙承租公寓，並明示對丙各負全部給付之責任時，甲、乙卻遲未給 付租金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00115', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列情形，何者在支付金錢後得請求受領者返還？', '["甲參加乙婚禮時所包之禮金", "乙花錢請丙代考轉學考，丙沒考上", "丙對丁有債務新臺幣10萬元，在履行期前提早清償", "丁不知對戊無給付義務，卻以清償債務之意而對戊為給付"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00116', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲向乙購買中古車一部，約定一星期後交付。交付當天乙駕駛該車前往指定地點途中，不料遭闖 紅燈之丙直接撞上致該車全毀。下列敘述，何者正確？', '["甲應給付買賣價金於乙", "乙無須負擔損害賠償責任", "乙應對甲負全部之賠償責任", "乙僅對甲負部分之賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00117', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲對乙有新臺幣100萬元債權，經起訴獲得勝訴判決確定後，聲請執行法院拍賣乙所有之A地， 由丙拍定。關於丙何時取得A地所有權，下列敘述，何者正確？', '["執行法院將所有權權利移轉證書發給丙時", "執行法院將A地之占有點交於丙時", "乙將A地之所有權移轉登記於丙時", "乙將A地之所有權狀交付於丙時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00118', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '物權可分為擔保物權與用益物權。下列何者非屬用益物權？', '["不動產役權", "區分地上權", "農育權", "質權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
